+        assert!(timeline.filter_kind.is_none());
+
+        // Cycle through all values
+        let mut count = 0;
+        loop {
+            timeline.cycle_kind();
+            count += 1;
+            if timeline.filter_kind.is_none() {
+                break;
+            }
+            assert!(count < 20, "Infinite loop in cycle_kind");
+        }
+
+        // Should have cycled through all 7 kinds + back to None
+        assert_eq!(count, 8);
+    }
